#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

using namespace std;

string preprocess(const string& s) {
    if (s.empty()) return "^$";
    string ret = "^";
    for (int i = 0; i < s.length(); i++) {
        ret += "#" + s.substr(i, 1);
    }
    ret += "#$";
    return ret;
}

string longestPalindrome(string s) {
    string T = preprocess(s);
    int n = T.length();
    vector<int> P(n, 0);
    int C = 0, R = 0;
    for (int i = 1; i < n - 1; i++) {
        int i_mirror = 2 * C - i;

        if (R > i) {
            P[i] = min(R - i, P[i_mirror]);
        } else {
            P[i] = 0;
        }
        while (T[i + 1 + P[i]] == T[i - 1 - P[i]]) {
            P[i]++;
        }
        if (i + P[i] > R) {
            C = i;
            R = i + P[i];
        }
    }
    int maxLen = 0;
    int centerIndex = 0;
    for (int i = 1; i < n - 1; i++) {
        if (P[i] > maxLen) {
            maxLen = P[i];
            centerIndex = i;
        }
    }

    int start = (centerIndex - maxLen) / 2;
    return s.substr(start, maxLen);
}

int main()
{
    string s;
    cin >> s;
    cout << longestPalindrome(s) << endl;
    return 0;
}
